CREATE TABLE IF NOT EXISTS public.country_pages (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  slug text NOT NULL UNIQUE,
  name_ru text NOT NULL,
  name_en text NOT NULL,
  currency text NOT NULL,
  region text NOT NULL,
  flag_emoji text NOT NULL,
  h1 text NOT NULL,
  meta_title text NOT NULL,
  meta_description text NOT NULL,
  intro_text text,
  keyword text NOT NULL,
  priority smallint NOT NULL DEFAULT 2,
  published boolean NOT NULL DEFAULT true,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now()
);

GRANT SELECT ON public.country_pages TO anon, authenticated;
GRANT ALL ON public.country_pages TO service_role;

ALTER TABLE public.country_pages ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Published country pages viewable by everyone" ON public.country_pages;
CREATE POLICY "Published country pages viewable by everyone"
  ON public.country_pages FOR SELECT
  USING (published = true);

ON CONFLICT (slug) DO NOTHING;